class HybridBridge(
    private val activity: Activity,
    private val webView: WebView
) {
    private var pendingNotificationPermissionCallback: String? = null

    @JavascriptInterface
    fun cameraAccess(): String {
        return JSONObject().put("status", "available").toString()
    }

    @JavascriptInterface
    fun getLocalStorage(key: String): String {
        val prefs = activity.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
        return prefs.getString(key, "") ?: ""
    }

    @JavascriptInterface
    fun setLocalStorage(key: String, value: String): Boolean {
        val prefs = activity.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
        return prefs.edit().putString(key, value).commit()
    }

    @JavascriptInterface
    fun clearLocalStorage(): Boolean {
        val prefs = activity.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
        return prefs.edit().clear().commit()
    }

    @JavascriptInterface
    fun requestPushNotifications(callbackId: String) {
        pendingNotificationPermissionCallback = callbackId
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            if (ContextCompat.checkSelfPermission(activity, Manifest.permission.POST_NOTIFICATIONS) == PackageManager.PERMISSION_GRANTED) {
                onNotificationPermissionResult(true)
            } else {
                if (activity is HybridWebViewActivity) {
                    activity.notificationPermissionLauncher.launch(Manifest.permission.POST_NOTIFICATIONS)
                } else {
                    onNotificationPermissionResult(false)
                }
            }
        } else {
            onNotificationPermissionResult(true)
        }
    }

    fun onNotificationPermissionResult(granted: Boolean) {
        val callbackId = pendingNotificationPermissionCallback ?: return
        pendingNotificationPermissionCallback = null
        val payload = JSONObject()
            .put("callbackId", callbackId)
            .put("granted", granted)
            .toString()
        webView.post {
            webView.evaluateJavascript(
                "window.__nativeBridge && window.__nativeBridge.onPushPermissionResult($payload);",
                null
            )
        }
    }

    @JavascriptInterface
    fun openCamera(callbackId: String) {
        val intent = Intent(MediaStore.ACTION_IMAGE_CAPTURE)
        if (intent.resolveActivity(activity.packageManager) != null && activity is HybridWebViewActivity) {
            activity.startActivity(intent)
        }
    }

    @JavascriptInterface
    fun sendDeviceToken(token: String) {
        val prefs = activity.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
        prefs.edit().putString(KEY_DEVICE_TOKEN, token).apply()
    }

    @JavascriptInterface
    fun notifyWeb(title: String, body: String) {
        val notification = NotificationCompat.Builder(activity, HybridWebViewActivity.NOTIFICATION_CHANNEL_ID)
            .setSmallIcon(android.R.drawable.ic_dialog_info)
            .setContentTitle(title)
            .setContentText(body)
            .setPriority(NotificationCompat.PRIORITY_DEFAULT)
            .setAutoCancel(true)
            .build()

        NotificationManagerCompat.from(activity).notify((System.currentTimeMillis() % Int.MAX_VALUE).toInt(), notification)
    }

    companion object {
        private const val PREFS_NAME = "hybrid_webview_storage"
        private const val KEY_DEVICE_TOKEN = "device_token"
    }
